# Multi-task adapter fusion — serving 10+ adapters from one base
import torch, torch.nn as nn

class AdapterRegistry:
    def __init__(self, base_model):
        self.base = base_model
        self.adapters = {}  # task_id -> LoRA weight dict
        self.active_adapter = None

    def register(self, task_id, lora_weights):
        self.adapters[task_id] = lora_weights

    def fuse_adapters(self, task_ids, weights=None):
        """Fuse multiple adapters by weighted average of their deltas."""
        if weights is None:
            weights = [1.0 / len(task_ids)] * len(task_ids)
        merged_delta = {}
        for task_id, w in zip(task_ids, weights):
            lora = self.adapters[task_id]
            for key in lora:
                if key not in merged_delta:
                    merged_delta[key] = torch.zeros_like(lora[key])
                merged_delta[key] += w * lora[key]
        return merged_delta

# Inference: merge adapter into base (or use forward hooks)
def merge_into_base(base_state_dict, adapter_delta, alpha=16.0, r=8):
    """W' = W + α/r * (BA)"""
    scaling = alpha / r
    merged = {}
    for key in base_state_dict:
        if key.endswith("weight") and key.replace("weight", "lora_A") in adapter_delta:
            A = adapter_delta[key.replace("weight", "lora_A")]
            B = adapter_delta[key.replace("weight", "lora_B")]
            merged[key] = base_state_dict[key] + scaling * (A @ B)
        else:
            merged[key] = base_state_dict[key]
    return merged

# ponytail: 50 adapters × 50MB = 2.5GB storage; LRU cache on GPU holds 4 hottest
